func normalizeSQL(sql string) string {
	var b strings.Builder
	spacePending := false

	runes := []rune(strings.TrimSpace(sql))
	for i := 0; i < len(runes); i++ {
		r := runes[i]

		switch r {
		case '-':
			if i+1 < len(runes) && runes[i+1] == '-' {
				i += 2
				for i < len(runes) && runes[i] != '\n' && runes[i] != '\r' {
					i++
				}
				i--
				spacePending = b.Len() > 0
				continue
			}
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		case '/':
			if i+1 < len(runes) && runes[i+1] == '*' {
				i += 2
				for i+1 < len(runes) && !(runes[i] == '*' && runes[i+1] == '/') {
					i++
				}
				if i+1 < len(runes) {
					i++
				}
				spacePending = b.Len() > 0
				continue
			}
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		case 'r', 'R':
			if i+1 < len(runes) && (runes[i+1] == '\'' || runes[i+1] == '"') {
				if spacePending && b.Len() > 0 {
					b.WriteByte(' ')
					spacePending = false
				}
				b.WriteRune(r)
				i++
				i = writeQuotedSQL(&b, runes, i, true)
				continue
			}
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		case '\'', '"', rune(0x60):
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			i = writeQuotedSQL(&b, runes, i, false)
		case ' ', '\t', '\n', '\r':
			spacePending = b.Len() > 0
		default:
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		}
	}

	return strings.TrimSpace(b.String())
}

func writeQuotedSQL(b *strings.Builder, runes []rune, start int, raw bool) int {
	quote := runes[start]
	triple := quote != rune(0x60) &&
		start+2 < len(runes) &&
		runes[start+1] == quote &&
		runes[start+2] == quote

	b.WriteRune(quote)
	if triple {
		b.WriteRune(quote)
		b.WriteRune(quote)
	}

	i := start
	if triple {
		i += 3
	} else {
		i++
	}
	for i < len(runes) {
		r := runes[i]
		b.WriteRune(r)

		if triple {
			if r == quote && i+2 < len(runes) && runes[i+1] == quote && runes[i+2] == quote {
				i++
				b.WriteRune(runes[i])
				i++
				b.WriteRune(runes[i])
				return i
			}
			i++
			continue
		}

		if !raw && quote != rune(0x60) && r == '\\' && i+1 < len(runes) {
			i++
			b.WriteRune(runes[i])
			i++
			continue
		}
		if !raw && quote != rune(0x60) && r == quote && i+1 < len(runes) && runes[i+1] == quote {
			i++
			b.WriteRune(runes[i])
			i++
			continue
		}
		if r == quote {
			return i
		}
		i++
	}

	return len(runes) - 1
}

